mapper.select:
select message_id, session_id, agent_code, user_id, role, content, event_type, structured_json,
       reference_json, attachment_json, ragflow_message_id, create_time
from mag_agent_message
where session_id = #{sessionId}
  and user_id = #{userId}
order by create_time asc, message_id asc

mapper.delete:
delete from mag_agent_message
where session_id = #{sessionId}
  and user_id = #{userId}
